import { setup, assign, fromPromise } from 'xstate';

type SignupEvent =
  | { type: 'EMAIL.UPDATE'; value: string }
  | { type: 'EMAIL.SUBMIT' }
  | { type: 'PASSWORD.UPDATE'; value: string }
  | { type: 'PASSWORD.SUBMIT' }
  | { type: 'CONFIRM.UPDATE'; value: string }
  | { type: 'CONFIRM.SUBMIT' }
  | { type: 'BACK' };

type SignupContext = {
  email: string;
  password: string;
  confirm: string;
  error?: string;
};

const checkEmailUnique = fromPromise<{ unique: boolean }, { email: string }>(
  async ({ input }) => {
    const res = await fetch(`/api/check-email?email=${encodeURIComponent(input.email)}`);
    if (!res.ok) throw new Error('Network error');
    return res.json();
  }
);

export const signupMachine = setup({
  types: {
    context: {} as SignupContext,
    events: {} as SignupEvent,
  },
  actors: { checkEmailUnique },
  guards: {
    passwordsMatch: ({ context }) => context.password === context.confirm,
  },
}).createMachine({
  id: 'signup',
  initial: 'email',
  context: { email: '', password: '', confirm: '' },
  states: {
    email: {
      initial: 'editing',
      states: {
        editing: {
          on: {
            'EMAIL.UPDATE': {
              actions: assign({ email: ({ event }) => event.value }),
            },
            'EMAIL.SUBMIT': 'validating',
          },
        },
        validating: {
          invoke: {
            src: 'checkEmailUnique',
            input: ({ context }) => ({ email: context.email }),
            onDone: [
              {
                guard: ({ event }) => event.output.unique,
                target: '#signup.password',
              },
              {
                target: 'editing',
                actions: assign({ error: 'Email already taken' }),
              },
            ],
            onError: {
              target: 'editing',
              actions: assign({ error: 'Validation failed' }),
            },
          },
        },
      },
    },
    password: {
      on: {
        'PASSWORD.UPDATE': {
          actions: assign({ password: ({ event }) => event.value }),
        },
        'PASSWORD.SUBMIT': 'confirm',
        BACK: 'email',
      },
    },
    confirm: {
      on: {
        'CONFIRM.UPDATE': {
          actions: assign({ confirm: ({ event }) => event.value }),
        },
        'CONFIRM.SUBMIT': {
          guard: 'passwordsMatch',
          target: 'done',
        },
        BACK: 'password',
      },
    },
    done: { type: 'final' },
  },
});
