import { setup, assign } from 'xstate';

type DownloadEvent =
  | { type: 'START' }
  | { type: 'PROGRESS'; value: number }
  | { type: 'PAUSE' }
  | { type: 'RESUME' }
  | { type: 'COMPLETE' }
  | { type: 'FAIL'; error: string }
  | { type: 'RESET' };

type DownloadContext = {
  progress: number;
  error?: string;
};

export const downloadMachine = setup({
  types: {
    context: {} as DownloadContext,
    events: {} as DownloadEvent,
  },
  guards: {
    canPause: ({ context }) => context.progress < 100,
  },
  actions: {
    setProgress: assign({
      progress: ({ event }) =>
        event.type === 'PROGRESS' ? Math.min(100, Math.max(0, event.value)) : 0,
    }),
    reset: assign({ progress: 0, error: undefined }),
  },
}).createMachine({
  id: 'download',
  initial: 'idle',
  context: { progress: 0 },
  states: {
    idle: {
      on: { START: { target: 'downloading', actions: 'reset' } },
    },
    downloading: {
      on: {
        PROGRESS: { actions: 'setProgress' },
        PAUSE: { guard: 'canPause', target: 'paused' },
        COMPLETE: 'done',
        FAIL: {
          target: 'error',
          actions: assign({ error: ({ event }) => event.error }),
        },
      },
    },
    paused: {
      on: { RESUME: 'downloading', RESET: { target: 'idle', actions: 'reset' } },
    },
    done: {
      on: { RESET: { target: 'idle', actions: 'reset' } },
    },
    error: {
      on: { RESET: { target: 'idle', actions: 'reset' } },
    },
  },
});
```

The `canPause` guard prevents PAUSE firing when progress already hit 100, and PAUSE is only handled in the `downloading` state — so by structure, pause is impossible from any other state.

