import { setup, assign, fromObservable } from 'xstate';
import { Observable } from 'rxjs';

type WsEvent = { type: 'message'; data: unknown };

const wsActor = fromObservable<WsEvent, { url: string }>(({ input }) =>
  new Observable<WsEvent>((sub) => {
    const ws = new WebSocket(input.url);
    ws.onmessage = (e) => {
      try {
        sub.next({ type: 'message', data: JSON.parse(e.data) });
      } catch {
        sub.next({ type: 'message', data: e.data });
      }
    };
    ws.onerror = (e) => sub.error(e);
    ws.onclose = () => sub.complete();
    return () => ws.close();
  })
);

type Ctx = { messages: unknown[]; url: string };
type Ev =
  | { type: 'CONNECT'; url: string }
  | { type: 'DISCONNECT' }
  // forwarded from the observable actor
  | { type: 'message'; data: unknown };

export const wsMachine = setup({
  types: { context: {} as Ctx, events: {} as Ev },
  actors: { wsActor },
}).createMachine({
  id: 'ws',
  initial: 'disconnected',
  context: { messages: [], url: '' },
  states: {
    disconnected: {
      on: {
        CONNECT: {
          target: 'connected',
          actions: assign({ url: ({ event }) => event.url }),
        },
      },
    },
    connected: {
      invoke: {
        src: 'wsActor',
        input: ({ context }) => ({ url: context.url }),
      },
      on: {
        message: {
          actions: assign({
            messages: ({ context, event }) => [...context.messages, event.data],
          }),
        },
        DISCONNECT: 'disconnected',
      },
    },
  },
});
```

`fromObservable` auto-forwards every emitted value as an event to the parent machine — so the `message` event handler picks it up and appends to context.

