import { pipe } from 'fp-ts/function';
import * as E from 'fp-ts/Either';

export type ValidationError = { field: 'email'; message: string };
export type Email = string & { readonly __brand: 'Email' };

const err = (message: string): ValidationError => ({ field: 'email', message });

const nonEmpty = (s: string): E.Either<ValidationError, string> =>
  s.trim().length > 0 ? E.right(s) : E.left(err('Email is required'));

const hasAt = (s: string): E.Either<ValidationError, string> =>
  s.includes('@') ? E.right(s) : E.left(err("Email must contain '@'"));

const underMaxLen = (s: string): E.Either<ValidationError, string> =>
  s.length < 254 ? E.right(s) : E.left(err('Email must be < 254 chars'));

export const validateEmail = (s: string): E.Either<ValidationError, Email> =>
  pipe(
    nonEmpty(s),
    E.chain(hasAt),
    E.chain(underMaxLen),
    E.map((v) => v as Email)
  );
```

`E.chain` short-circuits on the first Left, so you get fail-fast semantics. For accumulating all errors, swap Either for `Validation` / `Either` with a semigroup of errors.

```ts
import { Effect, Context, Layer } from 'effect';

interface Config { readonly apiUrl: string; readonly defaultUser: User }
const Config = Context.GenericTag<Config>('Config');

interface User { id: string; name: string }
class UserNotFound { readonly _tag = 'UserNotFound'; constructor(readonly id: string) {} }

const fetchUser = (id: string): Effect.Effect<User, UserNotFound, Config> =>
  Effect.gen(function* () {
    const cfg = yield* Config;
    const res = yield* Effect.tryPromise({
      try: () => fetch(`${cfg.apiUrl}/users/${id}`),
      catch: () => new UserNotFound(id),
    });
    if (res.status === 404) return yield* Effect.fail(new UserNotFound(id));
    return (yield* Effect.promise(() => res.json())) as User;
  });

const program = (id: string) =>
  Effect.gen(function* () {
    const cfg = yield* Config;
    const user = yield* fetchUser(id).pipe(
      Effect.catchTag('UserNotFound', () => Effect.succeed(cfg.defaultUser))
    );
    return user;
  });

const ConfigLive = Layer.succeed(Config, {
  apiUrl: 'https://api.example.com',
  defaultUser: { id: 'anon', name: 'Anonymous' },
});

// Run
Effect.runPromise(program('42').pipe(Effect.provide(ConfigLive))).then(console.log);
```

`Effect.catchTag` narrows on the `_tag` discriminator — only `UserNotFound` is handled, any other error bubbles up with its type intact.

