```ts
import { Effect, Context, Layer } from 'effect';

// --- Logger ---
interface Logger {
  readonly info: (msg: string) => Effect.Effect<void>;
  readonly error: (msg: string) => Effect.Effect<void>;
}
const Logger = Context.GenericTag<Logger>('Logger');

const LoggerLive = Layer.succeed(Logger, {
  info: (msg) => Effect.sync(() => console.log(`[INFO] ${msg}`)),
  error: (msg) => Effect.sync(() => console.error(`[ERROR] ${msg}`)),
});

// --- Database ---
interface Database {
  readonly query: <A>(sql: string) => Effect.Effect<A[]>;
}
const Database = Context.GenericTag<Database>('Database');

// DB depends on Logger (to log queries)
const DatabaseLive = Layer.effect(
  Database,
  Effect.gen(function* () {
    const log = yield* Logger;
    return {
      query: <A>(sql: string) =>
        Effect.gen(function* () {
          yield* log.info(`SQL: ${sql}`);
          return [] as A[];
        }),
    };
  })
);

// --- Program using both ---
const program = Effect.gen(function* () {
  const log = yield* Logger;
  const db = yield* Database;
  yield* log.info('starting');
  const users = yield* db.query<{ id: string }>('SELECT id FROM users');
  yield* log.info(`got ${users.length} users`);
});

// --- Wire layers: Database needs Logger, so merge or provide ---
const AppLayer = Layer.provideMerge(DatabaseLive, LoggerLive);

Effect.runPromise(program.pipe(Effect.provide(AppLayer)));
```

`Layer.provideMerge` satisfies Database's dependency on Logger while keeping Logger available to the program too.

