import { Observable } from 'rxjs';
import { debounceTime, distinctUntilChanged, switchMap, filter } from 'rxjs/operators';

interface Result { id: string; title: string }
declare function searchApi(query: string): Observable<Result[]>;

export function typeahead(input$: Observable<string>): Observable<Result[]> {
  return input$.pipe(
    debounceTime(250),
    distinctUntilChanged(),
    filter((q) => q.trim().length > 0),
    switchMap((q) => searchApi(q))
  );
}
```

`switchMap` is the key: when a new input arrives, it unsubscribes from the previous inner `searchApi` observable — auto-cancelling stale in-flight requests (assuming your `searchApi` wires up `AbortController` on unsubscribe).

