import { pipe } from 'fp-ts/function';
import * as E from 'fp-ts/Either';

export type ValidationError = { field: 'email'; message: string };
export type Email = string & { readonly __brand: 'Email' };

const err = (message: string): ValidationError => ({ field: 'email', message });

const nonEmpty = (s: string): E.Either<ValidationError, string> =>
  s.trim().length > 0 ? E.right(s) : E.left(err('Email is required'));

const hasAt = (s: string): E.Either<ValidationError, string> =>
  s.includes('@') ? E.right(s) : E.left(err("Email must contain '@'"));

const underMaxLen = (s: string): E.Either<ValidationError, string> =>
  s.length < 254 ? E.right(s) : E.left(err('Email must be < 254 chars'));

export const validateEmail = (s: string): E.Either<ValidationError, Email> =>
  pipe(
    nonEmpty(s),
    E.chain(hasAt),
    E.chain(underMaxLen),
    E.map((v) => v as Email)
  );
```

`E.chain` short-circuits on the first Left, so you get fail-fast semantics. For accumulating all errors, swap Either for `Validation` / `Either` with a semigroup of errors.

