// --- Commands ---
export type BankCommand =
  | { type: 'Deposit'; amountCents: number }
  | { type: 'Withdraw'; amountCents: number };

// --- Events ---
export type BankEvent =
  | { type: 'Deposited'; amountCents: number }
  | { type: 'Withdrawn'; amountCents: number };

// --- State ---
export interface BankState { balanceCents: number }

export interface Decider<S, C, E> {
  decide(command: C, state: S): E[];
  evolve(state: S, event: E): S;
  initial: S;
}

export const bankAccount: Decider<BankState, BankCommand, BankEvent> = {
  initial: { balanceCents: 0 },

  decide(command, state) {
    switch (command.type) {
      case 'Deposit':
        if (command.amountCents <= 0) throw new Error('Amount must be positive');
        return [{ type: 'Deposited', amountCents: command.amountCents }];

      case 'Withdraw':
        if (command.amountCents <= 0) throw new Error('Amount must be positive');
        if (command.amountCents > state.balanceCents) {
          throw new Error('Insufficient funds');
        }
        return [{ type: 'Withdrawn', amountCents: command.amountCents }];
    }
  },

  evolve(state, event) {
    switch (event.type) {
      case 'Deposited':
        return { balanceCents: state.balanceCents + event.amountCents };
      case 'Withdrawn':
        return { balanceCents: state.balanceCents - event.amountCents };
    }
  },
};
```

The Decider is a pure trio — no I/O. Infrastructure (event store, bus) lives outside.

```ts
export interface EventStore<E> {
  readStream(streamId: string): Promise<{ events: E[]; version: number }>;
  appendToStream(streamId: string, events: E[], expectedVersion: number): Promise<void>;
}

export interface Decider<S, C, E> {
  decide(command: C, state: S): E[];
  evolve(state: S, event: E): S;
  initial: S;
}

export class ConcurrencyError extends Error {
  constructor(public readonly expected: number, public readonly actual: number) {
    super(`Concurrency conflict: expected v${expected}, got v${actual}`);
  }
}

export function makeCommandHandler<S, C, E>(
  decider: Decider<S, C, E>,
  store: EventStore<E>,
  streamIdOf: (command: C) => string
) {
  return async function handle(command: C): Promise<void> {
    const streamId = streamIdOf(command);

    // 1. Load
    const { events, version } = await store.readStream(streamId);

    // 2. Rebuild state
    const state = events.reduce(decider.evolve, decider.initial);

    // 3. Decide
    const newEvents = decider.decide(command, state);
    if (newEvents.length === 0) return;

    // 4. Append with optimistic concurrency
    try {
      await store.appendToStream(streamId, newEvents, version);
    } catch (err) {
      // Translate store's concurrency error into a domain one
      if ((err as { code?: string }).code === 'WrongExpectedVersion') {
        throw new ConcurrencyError(version, -1);
      }
      throw err;
    }
  };
}
```

On conflict, a retry loop (usually with exponential backoff + max attempts) is idiomatic — reload the stream and re-run `decide` against the fresher state.

```ts
// --- Events (reused from cart aggregate) ---
type ItemAdded = { type: 'ItemAdded'; cartId: string; sku: string; qty: number; priceCents: number };
type ItemRemoved = { type: 'ItemRemoved'; cartId: string; sku: string; qty: number; priceCents: number };
type CartCreated = { type: 'CartCreated'; cartId: string };
export type ShoppingCartEvent = CartCreated | ItemAdded | ItemRemoved;

// --- Read model ---
export interface CartSummary {
  id: string;
  itemCount: number;
  totalCents: number;
}

const empty = (id: string): CartSummary => ({ id, itemCount: 0, totalCents: 0 });

export function project(
  state: CartSummary | undefined,
  event: ShoppingCartEvent
): CartSummary {
  switch (event.type) {
    case 'CartCreated':
      return empty(event.cartId);
    case 'ItemAdded': {
      const s = state ?? empty(event.cartId);
      return {
        ...s,
        itemCount: s.itemCount + event.qty,
        totalCents: s.totalCents + event.qty * event.priceCents,
      };
    }
    case 'ItemRemoved': {
      const s = state ?? empty(event.cartId);
      return {
        ...s,
        itemCount: Math.max(0, s.itemCount - event.qty),
        totalCents: Math.max(0, s.totalCents - event.qty * event.priceCents),
      };
    }
  }
}

// --- Driver: feed events from the store into a read-model repo ---
export interface CartSummaryRepo {
  get(id: string): Promise<CartSummary | undefined>;
  put(s: CartSummary): Promise<void>;
}

export async function handle(event: ShoppingCartEvent, repo: CartSummaryRepo) {
  const cartId = event.cartId;
  const current = await repo.get(cartId);
  await repo.put(project(current, event));
}
```

Note: `ItemRemoved` needs qty+price in the event (or a lookup) so the projector can decrement totals without reading aggregate state. This is a classic denormalization trade-off in event design.

**Tradeoffs:**

| Dimension | Replay full stream | Snapshotting |
|---|---|---|
| Simplicity | Dead simple — just fold | Adds versioning, serialization, invalidation |
| Load time | O(n) in stream length — slow for long-lived aggregates | O(1) + small tail — fast |
| Storage | Events only | Events + snapshots (extra space) |
| Schema evolution | Every replay goes through current `evolve` — easy to rewrite | Snapshots may be incompatible after model change — need versioned snapshots or rebuild |
| Debugging / audit | Full history always materialized | Snapshots hide intermediate states unless rebuilt |
| Correctness risk | Low — one code path | Higher — snapshot must stay in sync with evolve |

**Rule of thumb:** start without snapshots. Add them once a hot aggregate crosses ~1000+ events or p99 load latency exceeds your SLO. Always store the snapshot's schema version.

```ts
export interface Snapshot<S> {
  state: S;
  version: number;          // stream position when snapshot was taken
  schemaVersion: number;    // bump when S shape changes
}

export interface EventStore<E> {
  readStream(id: string, fromVersion?: number): Promise<{ events: E[]; version: number }>;
}

export interface SnapshotStore<S> {
  latest(streamId: string): Promise<Snapshot<S> | undefined>;
  save(streamId: string, snap: Snapshot<S>): Promise<void>;
}

export async function loadAggregate<S, E>(
  streamId: string,
  initial: S,
  evolve: (state: S, event: E) => S,
  currentSchemaVersion: number,
  events: EventStore<E>,
  snapshots: SnapshotStore<S>
): Promise<{ state: S; version: number }> {
  const snap = await snapshots.latest(streamId);
  const usable = snap && snap.schemaVersion === currentSchemaVersion ? snap : undefined;

  const startState = usable ? usable.state : initial;
  const fromVersion = usable ? usable.version + 1 : 0;

  const { events: tail, version } = await events.readStream(streamId, fromVersion);
  const finalState = tail.reduce(evolve, startState);
  return { state: finalState, version };
}
```
